-- 8. Link admin@clinic.com as superadmin
SELECT au.id, 'superadmin', 'admin@clinic.com', NULL
FROM auth.users au
WHERE au.email = 'admin@clinic.com'
ON CONFLICT (auth_id) DO UPDATE SET role = 'superadmin', email = EXCLUDED.email;
